class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = {}  # key -> (value, prev, next)
        self.head = None  # most recently used
        self.tail = None  # least recently used

    def _add(self, node):
        """Add node right after head."""
        if self.head is None:
            self.head = self.tail = node
        else:
            node.prev = None
            node.next = self.head
            self.head.prev = node
            self.head = node

    def _remove(self, node):
        """Remove a node from the list."""
        if node.prev:
            node.prev.next = node.next
            node.next.prev = node.prev
        else:
            self.head = node.next
        if node.next:
            node.next.prev = node.prev
        else:
            self.tail = node.prev

    def get(self, key):
        if key not in self.cache:
            return -1
        _, prev, nxt = self.cache[key]
        self._remove(self.cache[key])
        val_node = Node(key, self.cache[key][0], None)  # rebuild with fresh node
        self._add(val_node)
        self.cache[key] = (val_node.value, val_node.prev, val_node.next)
        return val_node.value

    def put(self, key, value):
        if key in self.cache:
            _, prev, nxt = self.cache[key]
            self._remove(self.cache[key])
            node = Node(key, value, None)
            self._add(node)
            self.cache[key] = (node.value, node.prev, node.next)
        else:
            if len(self.cache) >= self.capacity:
                evict_key, _, _ = self.cache[self.tail]
                del self.cache[evict_key]
                self.tail = self.tail.prev
            node = Node(key, value, None)
            self._add(node)
            self.cache[key] = (node.value, node.prev, node.next)


class Node:
    __slots__ = ('key', 'value', 'prev', 'next')

    def __init__(self, key, value, prev=None, next=None):
        self.key = key
        self.value = value
        self.prev = prev
        self.next = next
